var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"한참 헤맸는데 고마워. 덕분에 살았어.","JPN":"結構迷っていたから助かるよ。ありがとう。","ENG":"Thanks. I was so lost. You're a lifesaver.","TWN":"我迷路了很久，太謝謝你了。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"왜 그래? 뭐 잊은 일이라도 있어?","JPN":"どうしたの？　何か他の用事でもあるの？","ENG":"What's wrong? Did you forget something?","TWN":"怎麼了？是忘記什麼事了嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"아, 아니. 아무것도 아냐.","JPN":"い、いや。なんでもない。","ENG":"Oh, no. It's nothing.","TWN":"沒，沒什麼。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"그냥...... 누군가에게 도움이 된 건 오랜만이라.","JPN":"ただ……誰かの役に立てたのが久しぶりすぎてね。","ENG":"It's just that... It's been a while since I've been of help to anyone.","TWN":"只是……沒想到我能幫到別人。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":"쉽게 떠들지 마세요!","JPN":"簡単に言わないでください！","ENG":"You don't know what you're talking about!","TWN":"你根本不知道你在說些什麼！"},"stage":{"bg":"THRONE_VOID","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":"대적자가 무엇인지, 구원자가 무엇인지 압니까?","JPN":"敵対者が何なのか、救世主が何なのか、あなたは知っているんですか？","ENG":"Have you any idea what it means to be an Antagonist, or the Savior?","TWN":"你知道敵對者是什麼，救贖者是什麼嗎？"},"stage":{"bg":"THRONE_VOID","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":"의무가 무엇인지, 맹세가 무엇인지 아느냐고요!","JPN":"義務が何なのか、誓いが何なのか知っているのかって聞いているんです！","ENG":"What your mission is, what your vows are!","TWN":"你知道他們的義務是什麼，誓言是什麼嗎！"},"stage":{"bg":"THRONE_VOID","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":"저에게는 이제, 이것밖에 남지 않았단 말입니다!!","JPN":"僕にはもう、これしか残っていないんです！！","ENG":"Those are all I have left!","TWN":"對我來說，如今這就是我的全部了！！"},"stage":{"bg":"THRONE_VOID","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"사장님과의 대화가 잘 안 풀린 모양이군요.","JPN":"社長との話がうまくいかなったようですね。","ENG":"I see that your talk with Boss didn't go so well.","TWN":"看來你和老闆的談話不是很順利。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……부사장님.","JPN":"……副社長。","ENG":"...Vice President.","TWN":"……副總。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"등교하는 날도 아닌데 학교에 오다니 성실하네요.","JPN":"登校日でもないのに学校に来るなんて、真面目ですね。","ENG":"How diligent of you to come to school, even when it's not a school day.","TWN":"今天明明不用上學，你還來學校，很認真喔。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"제가 다니던 때와는 교실 풍경도 많이 달라졌어요. 옛날 생각이 나는군요.","JPN":"私が通ってた頃とは教室の様子もだいぶ変わりました。昔を思い出しますね。","ENG":"It's changed so much since I attended here. Still, it brings back memories.","TWN":"學校變好多，和我就讀的時候好不一樣。令我想起以前的事呢。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"세무 조사도 받는다고 하지 않았어? 이런 데 있어도 돼?","JPN":"税務調査も受けるって言ってなかった？　こんなところにいてもいいの？","ENG":"Didn't you say we were being tax audited? Shouldn't you be at work doing that?","TWN":"副總在這裡沒關係嗎？不是要準備稅務調查的事嗎？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"애사심 넘치는 모습이 보기 좋네요.","JPN":"愛社心溢れる姿、いいですね。","ENG":"I appreciate your loyalty to our company.","TWN":"看到你這麼為公司著想，我很高興呢。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 괜찮습니다. 회사 경영하면서 이런 일이 한두 번 있었던 것도 아니고 말이죠.","JPN":"でも、大丈夫です。会社を経営してきて、こんなことは珍しいことでもありませんし。","ENG":"But don't worry. It's not like it's my first time being audited while managing a firm.","TWN":"沒事的，經營公司這麼久，也不是第一次遇到這種事。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"굿즈 시장에 도전했다가 실패한 건 조금 뼈아프지만.","JPN":"グッズ事業にチャレンジして失敗したのはちょっと痛いですけど。","ENG":"Although it is painful to see that our little merchandise venture ended as a flop.","TWN":"不過挑戰販賣周邊商品失敗確實還蠻傷的。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"한 가지만 대답해 줘.","JPN":"一つだけ答えて。","ENG":"I want you to answer me this one question.","TWN":"回答我一個問題就好。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"나더러 다시 학교에 다니라고 한 것도 그 계획인지 뭔지 때문이었어?","JPN":"私にまた学校に通うように言ったのも、その計画とかのためだった？","ENG":"Was making me go back to school also a part of the plan?","TWN":"副總要我回學校上課也是因為計畫的關係嗎？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어느 쪽인지 묻는다면, 제가 아는 한에서는 아닙니다.","JPN":"どちらだったかという答えでしたら、私の知ってる限りでは違います。","ENG":"To my knowledge, the answer is no.","TWN":"你要問的話，據我所知不是的。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네헤모트는 그 이전까지 특별한 움직임을 보여 준 적이 없었어요.","JPN":"ネヘモトはその前まで特に動きを見せたことがありませんでした。","ENG":"Until that point, Nehemoth had not shown any signs of movement.","TWN":"貝赫莫特在那之前從來沒有暴露出特別的行動。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"마왕 중 한 명이 움직일 거라는 확신은 있었지만, 그게 네헤모트는 아니었어요.","JPN":"魔王のうちの一人が動くという確信はありましたが、それがネヘモトではなかったのです。","ENG":"We were expecting one of the Demon Lords to make a move, but Nehemoth was not one of them.","TWN":"雖然確定其中一個魔王有行動，但那不是貝赫莫特。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"오히려 지식의 호수와 최초의 인형 쪽이 경계 대상이었죠.","JPN":"むしろ、知識の湖と最初の人形の方が警戒対象でした。","ENG":"Rather, we were more cautious about the Lake of Knowledge and the Original Puppet.","TWN":"反而知識湖水和最初的人偶才是需要注意的對象。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그럼 여기서 레이 선배와 마주친 게… 그냥 우연이라고?","JPN":"じゃあ、ここでレイ先輩と出会ったのは……ただの偶然？","ENG":"So then, meeting Ray here was... just a coincidence?","TWN":"所以我會在這裡遇見雷伊前輩…只是巧合？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"계획이 정교해질수록 실패할 확률은 커집니다.","JPN":"計画が緻密になるほど、失敗する確率は高くなります。","ENG":"The more detailed the plan, the more likely it will fail.","TWN":"計畫越縝密，失敗的機率就越高。"},"stage":{"bg":"ALPHA_07","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어느 시점부터는 변수에 대한 대응책을 마련해 두는 것이 고작이죠.","JPN":"ある時点からは、変数に対する対応策を準備しておくので精一杯になります。","ENG":"All we could do from then on was finding countermeasures to the variables.","TWN":"從某個時候開始，最多就只是預備好變數的對策而已。"},"stage":{"bg":"ALPHA_07","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"모든 걸 완벽하게 통제하겠다는 발상은 결국 실패로 돌아가게 되어 있어요.","JPN":"全てを完璧にコントロールしようという発想は、結局失敗します。","ENG":"Attempting to completely control everything will inevitably result in failure.","TWN":"想要完美控制一切的想法，最終只會導向失敗。"},"stage":{"bg":"ALPHA_07","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"자기 인생이 그동안 남들에게 꼭두각시처럼 놀아난 것 아닐까 두려울 겁니다, 미나 양.","JPN":"自分の人生が今まで他人によって操り人形よろしく遊ばれていたのではないか、と怖れているんですね。ミナさん。","ENG":"I know you are scared that your life may be in the hands of others, Mina.","TWN":"米娜，你害怕自己的人生是否只是受人操控的魁儡是吧。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"제 말 몇 마디에 마음이 바뀌길 기대하진 않아요.","JPN":"私の二言三言で心が変わるとは思っていません。","ENG":"I also do not expect my saying will suddenly change your mind.","TWN":"我不期待因為我的幾句話就可以改變你的想法。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 미나 양이 했던 노력들을 전부 부정하진 않았으면 좋겠습니다.","JPN":"ですが、ミナさんが努力してきたことの全てを否定しないでほしいです。","ENG":"However, I'd like you to not dismiss all the effort you put in, Mina.","TWN":"但是米娜，我希望你不要因此而否定過去所有的努力。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그건 미나 양 본인에게 잔인한 선택이 될 테니까요.","JPN":"それはミナさん本人にとって、残酷な選択になるでしょうから。","ENG":"Because doing so would be a cruel decision for you.","TWN":"這對你本人會是很殘忍的決定。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>그라운드 원 도시관리국에서 안내드립니다. </color>","JPN":"<color=#ffd34c>グラウンド・ワンの都市管理局からお知らせします。</color>","ENG":"<color=#ffd34c>This is an announcement from Ground One, City Management.</color>","TWN":"<color=#ffd34c>G1城市管理局通知。</color>"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현재, T-7 물류구역에 제 3종 침식체가 발생한 것이 확인되었습니다.</color>","JPN":"<color=#ffd34c>現在、T-7の物流区域にて、第3種侵食体が出現したことが確認されました。</color>","ENG":"<color=#ffd34c>Currently, a reporting of a Category 3 C.O. sighting has been confirmed in the Sector T-7 loading docks.</color>","TWN":"<color=#ffd34c>目前在T-7物流區發現3類侵蝕體。</color>"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>시민 여러분께서는 상황 해제 전까지 접근을 삼가주시기 바랍니다.</color>","JPN":"<color=#ffd34c>市民の皆さんは状況が解除されるまで、接近をお控えください。</color>","ENG":"<color=#ffd34c>All citizens are advised to avoid the area until the crisis has been resolved.</color>","TWN":"<color=#ffd34c>在情況解除前，各位市民請勿隨意靠近。</color>"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"3종…….","JPN":"第3種……","ENG":"Category 3...","TWN":"3類……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양! 위험해요!","JPN":"ミナさん！　危険です！","ENG":"Mina! Watch out!","TWN":"米娜小姐！危險！！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"피해요!!","JPN":"避けて！！","ENG":"Get away from it!","TWN":"快閃開！！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아니! 여기서 물러날 순 없어!!","JPN":"いや！　ここで引き下がるわけにはいかない！！","ENG":"No! I can't stand down now!","TWN":"不行！不能在這裡退開！！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"저 녀석도 분명 충격을 받았을 거야!","JPN":"あいつもダメージを負ってるはず！","ENG":"I'm sure that thing took some real damage just now!","TWN":"這傢伙肯定也受到傷害了！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"확실하게 쓰러트리려면...... 지금이 기회야!!","JPN":"確実に倒すには……今しかない！！","ENG":"To take it down for sure... Now's our chance!!!","TWN":"要徹底打倒它……現在就是機會！！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그런 무모한 소릴!","JPN":"そんな無謀な……！","ENG":"That's too reckless!","TWN":"太魯莽了！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아무리 약해졌다고 해도 상대는 제 3종 이상의 고위 침식체입니다!","JPN":"弱っているとしても、相手は第3種以上の高位侵食体です！","ENG":"It may be weakened, but it's still at least a Category 3!","TWN":"不管變得再怎麼弱，那都是3級以上的高階侵蝕體啊！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양의 CRF 출력으로는 그림자의 방어 침식장을 뚫을 수 없어요!","JPN":"ミナさんのCRF出力じゃ、シャドウの防御侵食シールドを突破できません！","ENG":"Your CRF output's nowhere enough to penetrate the Shadow's Corruption barrier!","TWN":"米娜小姐的CRF輸出，是沒辦法穿透暗影的防禦侵蝕屏障的！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……그래. 맞아. 고위 침식체였어.","JPN":"……そう、そうだよ。高位侵食体だった。","ENG":"...Oh, right. That was a high-tier C.O.","TWN":"……沒錯，是高階侵蝕體。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그 애, 설마…….","JPN":"あの子、まさか……","ENG":"The girl... There's no way...","TWN":"她該不會……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네, 사장님. 무슨 일이시죠?","JPN":"はい、社長。どうかされましたか？","ENG":"Yes, Boss. Is there something you need?","TWN":"是，老闆，有什麼事嗎？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"지금 미나 양과 같이 있나?","JPN":"今、ミナ君と一緒かい？","ENG":"Are you with Mina right now?","TWN":"你現在和米娜在一起嗎？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……네. 개인 면담 중이었습니다. 부탁하셨던 대로.","JPN":"……はい。個人面談中でした。ご指示通り。","ENG":"...Yes. I was having a talk with her. Just like you asked.","TWN":"……對，我在跟她一對一談話，照老闆的吩咐。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"다른 건 아니네만, 아무래도 오늘 면접 본 지원자 때문에 말일세.","JPN":"実は、今日面接した志願者の件なんだが。","ENG":"I'm sure it's nothing, but the girl who we interviewed today.","TWN":"沒什麼，就是今天來面試的那位的小姐。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"관리부장 말로는 연락이 안 된다던데, 확인 좀 해 줄 수 있겠나?","JPN":"管理部長の話によると、連絡がつかないらしいんだ、確認してくれないか？","ENG":"Hana told me that she couldn’t get in touch with her. Could you check as well?","TWN":"管理部長說一直聯絡不上她，你可以幫我確認一下嗎？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"나쁜 예감은 언제나 잘 들어맞죠. 알겠습니다.","JPN":"悪い予感はいつもよく当たるものです。わかりました。","ENG":"Bad feelings always turn out to be right. I'll get on it right away.","TWN":"不好的預感總是很靈驗呢，知道了。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"사장님이야? 무슨 일인데?","JPN":"社長？　どうしたの？","ENG":"Was that Boss? Is something up?","TWN":"是老闆嗎？有什麼事？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"오늘 면접 때문이에요. 지원자가 정말 3종 침식체에게 덤비지 않았을지 걱정하시더군요.","JPN":"今日の面接の件です。志願者が本当に第3種侵食体にケンカを売ってないか、心配していました。","ENG":"It is about today's interview. He is worried that the girl will try to fight the Category 3 for real.","TWN":"就今天來面試的那位小姐，老闆擔心她會真的去對付3類侵蝕體。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"바보 같은 소리 하지 마. 그럴 리가….","JPN":"バカなこと言わないで。そんなはずが……","ENG":"Don't be stupid. There's no way...","TWN":"說什麼傻話，這怎麼可能…"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그 애 전화 번호 있어? 내가 걸어 볼게.","JPN":"あの子の電話番号、ある？　私がかけてみるよ。","ENG":"Do you have her number? I'll try calling her.","TWN":"有她的電話嗎？我打給她看看。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>지금은 고객님께서 전화를 받을 수 없습니다. 다음에 다시…</color>","JPN":"<color=#ffd34c>ただいま、電話に出ることができません。しばらく経ってから……</color>","ENG":"<color=#ffd34c>Sorry I can't take your call right now. Please leave your name, number...</color>","TWN":"<color=#ffd34c>您撥的用戶現在無法接通，請稍後再…</color>"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……젠장. 왜 하필 이럴 때.","JPN":"……くそ、よりによってこんな時に。","ENG":"...Ugh. But the timing...","TWN":"……該死，偏偏挑這種時候！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그러게 말이죠.","JPN":"そのとおりですね。","ENG":"Yes, the timing.","TWN":"就是啊。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"미나 양은 그럼 여기 계속 있을 건가요? 마침 차를 몰고 나왔는데.","JPN":"それでは、ミナさんはまだここに残りますか？　ちょうど車で来たんですが。","ENG":"Mina, are you going to stay here? I brought my car with me today.","TWN":"米娜，你要繼續在這裡嗎？我剛好有開車出來。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"가는 길에 좀 태워 줘, 부사장님. T-7 구역으로.","JPN":"ついでに乗せて、副社長。T-7区域に行く。","ENG":"Then could you give me a ride to Sector T-7?","TWN":"可以順便載我一程嗎，副總？我要去T-7。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};